//! AMQP `basic.qos` → Stoplight green-window-width mapping.
//!
//! AMQP `basic.qos` carries (`prefetch_count`, `prefetch_size`,
//! `global`). gnosis-antiqueue collapses this to two numbers:
//!
//! * `prefetch` → `Stoplight.green` (admission width per corridor cycle)
//! * `cycle`    → `Stoplight.cycle` (the corridor period; default 66
//!   ticks — the Grassmannian cycle C(12,2), matching the Aeon vertex
//!   count in the amplituhedron)
//!
//! The mapping is intentionally lossy: `prefetch_size` (byte-budget) has
//! no Stoplight counterpart and is ignored. A future revision can wire
//! it to the `vent` combiner — drop messages whose body exceeds the
//! budget — but that requires the Task #8 vent integration to land.

/// Grassmannian cycle: C(12,2) = 66 — the number of 2-plane vertices in
/// the 12-dimensional Aeon phase space.
pub const GRASSMANNIAN_CYCLE: u32 = 66;

/// QoS specification for a channel.
#[derive(Clone, Copy, Debug)]
pub struct QosSpec {
    /// `basic.qos prefetch_count`. Mapped 1:1 to `Stoplight.green` —
    /// the width of the admission window inside one corridor cycle.
    /// A prefetch of `k` means up to `k` messages may pass through the
    /// corridor in any single cycle.
    pub prefetch: u32,
    /// Corridor period in ticks. Default 66 (GRASSMANNIAN_CYCLE).
    pub cycle: u32,
    /// Certified per-message handler cost, in nanoseconds — the value-door
    /// cost class. This is AMQP `basic.qos prefetch_size`, which the original
    /// mapping (above) explicitly dropped: instead of a byte-budget we read it
    /// as the *attested* cost of running the handler for one message. It is the
    /// admission cert that the cost-aware publish path gates on
    /// (`Producer::publish_message_certified`): the door (corridor stagger) is
    /// opened only when this per-message work exceeds the per-message gate cost
    /// (`Gnosis.ValueDoorStoplight.certified_never_yellow`). `0` means
    /// "unattested" — the cost-aware path then conservatively stays on the
    /// default staggered door (treated as heavy). The default (size-gated)
    /// publish path ignores it entirely.
    pub handler_cost_ns: u64,
}

impl Default for QosSpec {
    fn default() -> Self {
        Self {
            prefetch: 1,
            cycle: GRASSMANNIAN_CYCLE,
            handler_cost_ns: 0,
        }
    }
}

impl QosSpec {
    /// AMQP-style constructor: `basic.qos(prefetch=k)` with the default
    /// Grassmannian 66-tick cycle.
    pub const fn prefetch(k: u32) -> Self {
        Self {
            prefetch: k,
            cycle: GRASSMANNIAN_CYCLE,
            handler_cost_ns: 0,
        }
    }

    /// As `prefetch`, but pin the corridor cycle explicitly.
    pub const fn with_cycle(prefetch: u32, cycle: u32) -> Self {
        Self {
            prefetch,
            cycle,
            handler_cost_ns: 0,
        }
    }

    /// Builder: attach the certified per-message handler cost (ns) — the
    /// value-door cost class read on the cost-aware publish path.
    pub const fn with_handler_cost_ns(mut self, handler_cost_ns: u64) -> Self {
        self.handler_cost_ns = handler_cost_ns;
        self
    }

    /// Grassmannian constructor: prefetch=1, cycle=66 (C(12,2)).
    /// The natural QoS for Aeon phase-space topologies.
    pub const fn grassmannian() -> Self {
        Self {
            prefetch: 1,
            cycle: GRASSMANNIAN_CYCLE,
            handler_cost_ns: 0,
        }
    }

    /// Three-lane constructor: prefetch=3 (one per FOIL lane), cycle=66.
    /// Matches the hope-jar 3-lane FOIL transport layout.
    pub const fn three_lane() -> Self {
        Self {
            prefetch: 3,
            cycle: GRASSMANNIAN_CYCLE,
            handler_cost_ns: 0,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn default_is_prefetch_one_grassmannian() {
        let q = QosSpec::default();
        assert_eq!(q.prefetch, 1);
        assert_eq!(q.cycle, GRASSMANNIAN_CYCLE);
        assert_eq!(q.cycle, 66);
    }

    #[test]
    fn prefetch_constructor_pins_grassmannian_cycle() {
        let q = QosSpec::prefetch(8);
        assert_eq!(q.prefetch, 8);
        assert_eq!(q.cycle, 66);
    }

    #[test]
    fn with_cycle_overrides() {
        let q = QosSpec::with_cycle(4, 32);
        assert_eq!(q.prefetch, 4);
        assert_eq!(q.cycle, 32);
    }

    #[test]
    fn grassmannian_constructor() {
        let q = QosSpec::grassmannian();
        assert_eq!(q.prefetch, 1);
        assert_eq!(q.cycle, GRASSMANNIAN_CYCLE);
    }

    #[test]
    fn three_lane_constructor() {
        let q = QosSpec::three_lane();
        assert_eq!(q.prefetch, 3);
        assert_eq!(q.cycle, GRASSMANNIAN_CYCLE);
    }
}
